public void initFromIssue(
    ReqTrans        _issueReqTrans,
    ReqSetupDim     _setupDim)
{
    next initFromIssue(_issueReqTrans, _setupDim);

    ReqGroup reqGroup = ReqGroup::find(_issueReqTrans.inventTable().ReqGroupId);

    if (reqGroup.CovRule == ReqCovType::Req && reqGroup.FWFTextBlockCopyFromSalesOrder)
    {
        if (_issueReqTrans.RefType == ReqRefType::Sales)
        {
            this.FWFTextBlockSalesLineFromRefRecId	= InventTransOriginSalesLine::salesLine(_issueReqTrans.InventTransOrigin).RecId;
        }
        else if (_issueReqTrans.RefType == ReqRefType::ProdLine || _issueReqTrans.RefType == ReqRefType::PmfFormulaLine)
        {
            this.FWFTextBlockProdBOMFromRefRecId = InventTransOriginProdBOM::prodBOM(_issueReqTrans.InventTransOrigin).RecId;
        }
    }
}

[SysClientCacheDataMethodAttribute(true)]
public display container displayHasTextblock()
{
    return FWFTextBlockHelper::hasTextblock(this);
}
